INSERT INTO email_drafts VALUES('192992ba-a94f-449e-bbb9-1b39a0199002','05ee1994-a747-42f1-86e3-3d00bab53283','GPU financing — a quick thought','{"html":"<!DOCTYPE html>\n<html>\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <style>\n    body { font-family: -apple-system, BlinkMacSystemFont, ''Segoe UI'', sans-serif; font-size: 15px; line-height: 1.6; color: #1a1a1a; max-width: 600px; margin: 0 auto; padding: 20px; }\n    p { margin: 0 0 16px; }\n    a { color: #2563eb; }\n    .signature { margin-top: 28px; color: #555; }\n  </style>\n</head>\n<body>\n  <p>Hi Marcus,</p>\n\n  <p>I''ll keep this short. Voltage Park is building serious GPU infrastructure — [https://voltagepark. The financing piece is where we can help.</p>\n\n  <p>We help GPU operators get a better debt structure by reducing residual value risk on the hardware. A lot of lenders still get stuck on one question: what are the GPUs worth at maturity? We solve for that.</p>\n\n  <p>The short version: lenders get more comfort on future hardware value, which can mean better LTV, longer tenor, or lower spread on your next cluster.</p>\n\n  <p>Would a 20-minute call with our founders be useful? Happy to work around your schedule.</p>\n\n  <div class=\"signature\">\n    <p>Josh Augustine<br>\n    Corgi<br>\n    <a href=\"https://corgi.xyz\">corgi.xyz</a></p>\n  </div>\n\n  \n</body>\n</html>","text":"Hi Marcus,\n\nI''ll keep this short. Voltage Park is building serious GPU infrastructure — [https://voltagepark. The financing piece is where we can help.\n\nWe help GPU operators get a better debt structure by reducing residual value risk on the hardware. A lot of lenders still get stuck on one question: what are the GPUs worth at maturity? We solve for that.\n\nThe short version: lenders get more comfort on future hardware value, which can mean better LTV, longer tenor, or lower spread on your next cluster.\n\nWould a 20-minute call with our founders be useful? Happy to work around your schedule.\n\nJosh Augustine\nCorgi\ncorgi.xyz"}','cold_intro_operator','draft','2026-03-21 02:37:38',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,NULL);
