INSERT INTO email_drafts VALUES('b6343f4c-e999-4671-960b-d4faddd14040','afac952e-4a14-4e64-90c1-db7e929f497e','Reducing residual value risk on your GPU fleet',unistr('Hi Chase,\u000a\u000aI''ll keep this short.\u000a\u000aCorgi provides a residual value floor on data-center GPUs — the part of the underwriting that makes lenders nervous about hardware value at maturity (typically 3–5 years out).\u000a\u000aFor an operator with a fleet like Crusoe AI''s — 20,000+ GPUs — this directly improves your cost of capital and gives lenders the comfort to offer better leverage, longer tenor, or tighter pricing.\u000a\u000aWe work with GPU owners and their lenders to make financing cleaner. Not adding complexity — removing the one piece that typically slows deals down.\u000a\u000aWorth a 20-minute call with our founders, Isaac and Josh, to see if this fits your current or upcoming financing plans?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — GPU Operator','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'chase@crusoe.ai');
INSERT INTO email_drafts VALUES('13851bcb-0f6f-49fa-8d01-9fd9813e4f1b','ce1b56b2-d20c-435f-8873-45fe63b331f3','GPU collateral protection for your lending portfolio',unistr('Hi Head,,\u000a\u000aQuick intro: Corgi builds residual value solutions for data-center GPUs.\u000a\u000aAs Head at Dell Financial Services, you''re likely evaluating AI infrastructure credit opportunities where GPU collateral at maturity is one of the harder underwriting questions.\u000a\u000aWe provide a residual value floor that removes that uncertainty — giving your IC a cleaner recovery assumption and more confidence to lend at better LTV.\u000a\u000aThe result: more GPU-backed loans deployed, with better downside protection built into the structure.\u000a\u000aOpen to a short call to see if this fits your current credit box?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Lender','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'dfs@dell.com');
