INSERT INTO email_drafts VALUES('42012072-33fd-40a9-a85e-4f09e9cbf50c','0406a95f-1172-4f73-9bb2-893fd848f486','GPU collateral protection for your lending portfolio',unistr('Hi President,,\u000a\u000aQuick intro: Corgi builds residual value solutions for data-center GPUs.\u000a\u000aAs President at Hewlett Packard Financial Services (HPFS), you''re likely evaluating AI infrastructure credit opportunities where GPU collateral at maturity is one of the harder underwriting questions.\u000a\u000aWe provide a residual value floor that removes that uncertainty — giving your IC a cleaner recovery assumption and more confidence to lend at better LTV.\u000a\u000aThe result: more GPU-backed loans deployed, with better downside protection built into the structure.\u000a\u000aOpen to a short call to see if this fits your current credit box?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — Lender','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'hpfs@hpe.com');
