INSERT INTO email_drafts VALUES('b180b4d3-26fb-4a3b-9970-e970a40b37b7','a09b06d4-22df-433a-aab3-a588813438d1','Reducing residual value risk on your GPU fleet',unistr('Hi Tanner,\u000a\u000aI''ll keep this short.\u000a\u000aCorgi provides a residual value floor on data-center GPUs — the part of the underwriting that makes lenders nervous about hardware value at maturity (typically 3–5 years out).\u000a\u000aFor an operator with a fleet like Massed Compute''s — 5,000+ GPUs — this directly improves your cost of capital and gives lenders the comfort to offer better leverage, longer tenor, or tighter pricing.\u000a\u000aWe work with GPU owners and their lenders to make financing cleaner. Not adding complexity — removing the one piece that typically slows deals down.\u000a\u000aWorth a 20-minute call with our founders, Isaac and Josh, to see if this fits your current or upcoming financing plans?\u000a\u000aBest,\u000aCorgi Team'),'Cold Intro — GPU Operator','draft','2026-03-23 00:25:00',NULL,'a',0,NULL,NULL,NULL,NULL,NULL,'tanner@massedcompute.com');
