PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE email_drafts (
      id            TEXT PRIMARY KEY,
      contact_id    TEXT NOT NULL REFERENCES contacts(id) ON DELETE CASCADE,
      subject       TEXT NOT NULL,
      body          TEXT NOT NULL,
      template_name TEXT,
      status        TEXT NOT NULL CHECK(status IN ('draft', 'approved', 'sent')) DEFAULT 'draft',
      created_at    TEXT NOT NULL DEFAULT (datetime('now'))
    , campaign_id TEXT, ab_variant TEXT DEFAULT 'a', sequence_day INTEGER DEFAULT 0, scheduled_at TEXT, sent_at TEXT, opened_at TEXT, clicked_at TEXT, from_email TEXT, to_email TEXT);
COMMIT;
